import { cookies } from "next/headers";
import { SignJWT, jwtVerify } from "jose";

import {
  SESSION_COOKIE_NAME,
  SESSION_ALG,
  SESSION_MAX_AGE,
  cookieOptions,
} from "@/lib/auth/config";
import {
  UnauthorizedError,
  ExpiredSessionError,
  ForbiddenError,
} from "@/lib/auth/errors";
import type { SessionUser, UserRole } from "@/types/auth";

/* ============================================
   Session Utilities
   JWT-based session management using jose.
   Works in both Node.js and Edge runtimes.
   ============================================ */

function getSecret(): Uint8Array {
  const secret = process.env.AUTH_SECRET;
  if (!secret) {
    throw new Error("AUTH_SECRET environment variable is required");
  }
  return new TextEncoder().encode(secret);
}

/** JWT payload shape (internal). */
type SessionPayload = {
  sub: string;
  email: string;
  name: string;
  role: UserRole;
  avatar?: string | null;
  iat: number;
  exp: number;
};

/**
 * Create a signed session JWT and set it as an httpOnly cookie.
 * Call this after successful authentication.
 */
export async function createSession(user: {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  avatar?: string | null;
}): Promise<void> {
  const token = await new SignJWT({
    sub: user.id,
    email: user.email,
    name: user.name,
    role: user.role,
    avatar: user.avatar ?? null,
  })
    .setProtectedHeader({ alg: SESSION_ALG })
    .setIssuedAt()
    .setExpirationTime(`${SESSION_MAX_AGE}s`)
    .sign(getSecret());

  const store = await cookies();
  store.set(SESSION_COOKIE_NAME, token, cookieOptions);
}

/**
 * Verify and decode the session JWT from the cookie.
 * Returns `null` if no session exists or the token is invalid.
 */
export async function getSession(): Promise<SessionUser> {
  const store = await cookies();
  const token = store.get(SESSION_COOKIE_NAME)?.value;

  if (!token) return null;

  try {
    const { payload } = await jwtVerify(token, getSecret(), {
      algorithms: [SESSION_ALG],
    });

    return {
      id: payload.sub as string,
      email: payload.email as string,
      name: payload.name as string,
      role: payload.role as UserRole,
      avatar: (payload.avatar as string | null) ?? null,
    };
  } catch {
    // Token is expired, malformed, or signature mismatch
    return null;
  }
}

/**
 * Get the currently authenticated user.
 * Returns `null` if not authenticated — does not throw.
 */
export async function getCurrentUser(): Promise<SessionUser> {
  return getSession();
}

/**
 * Require an authenticated user. Throws `UnauthorizedError` if
 * no valid session exists, or `ExpiredSessionError` if the
 * session token is present but expired.
 */
export async function requireUser(): Promise<NonNullable<SessionUser>> {
  const store = await cookies();
  const token = store.get(SESSION_COOKIE_NAME)?.value;

  if (!token) {
    throw new UnauthorizedError();
  }

  try {
    const { payload } = await jwtVerify(token, getSecret(), {
      algorithms: [SESSION_ALG],
    });

    return {
      id: payload.sub as string,
      email: payload.email as string,
      name: payload.name as string,
      role: payload.role as UserRole,
      avatar: (payload.avatar as string | null) ?? null,
    };
  } catch (err) {
    // Distinguish expired token from other errors
    if (err instanceof Error && err.name === "JWTExpired") {
      throw new ExpiredSessionError();
    }
    throw new UnauthorizedError();
  }
}

/**
 * Require the authenticated user to have one of the specified roles.
 * Throws `UnauthorizedError` if not logged in, `ForbiddenError` if
 * the user's role is not in the allowed list.
 */
export async function requireRole(
  ...allowedRoles: UserRole[]
): Promise<NonNullable<SessionUser>> {
  const user = await requireUser();

  if (!allowedRoles.includes(user.role)) {
    throw new ForbiddenError();
  }

  return user;
}

/**
 * Destroy the session by deleting the session cookie.
 */
export async function destroySession(): Promise<void> {
  const store = await cookies();
  store.delete(SESSION_COOKIE_NAME);
}

/* ============================================
   Authentication & Authorization Errors
   Custom error classes for granular handling.
   ============================================ */

/** Base error for all auth-related failures. */
export class AuthError extends Error {
  constructor(
    message: string,
    public code: string
  ) {
    super(message);
    this.name = "AuthError";
  }
}

/** Thrown when email/password combination is invalid. */
export class InvalidCredentialsError extends AuthError {
  constructor(message = "البريد الإلكتروني أو كلمة المرور غير صحيحة") {
    super(message, "INVALID_CREDENTIALS");
    this.name = "InvalidCredentialsError";
  }
}

/** Thrown when no session exists or the user is not authenticated. */
export class UnauthorizedError extends AuthError {
  constructor(message = "يجب تسجيل الدخول للوصول إلى هذه الصفحة") {
    super(message, "UNAUTHORIZED");
    this.name = "UnauthorizedError";
  }
}

/** Thrown when the authenticated user lacks the required role. */
export class ForbiddenError extends AuthError {
  constructor(message = "ليس لديك صلاحية للوصول إلى هذه الصفحة") {
    super(message, "FORBIDDEN");
    this.name = "ForbiddenError";
  }
}

/** Thrown when a session token has expired or is otherwise invalid. */
export class ExpiredSessionError extends AuthError {
  constructor(message = "انتهت صلاحية الجلسة، يرجى تسجيل الدخول مرة أخرى") {
    super(message, "EXPIRED_SESSION");
    this.name = "ExpiredSessionError";
  }
}

/** Thrown when too many login attempts have been made. */
export class RateLimitExceededError extends AuthError {
  constructor(message = "تم تجاوز عدد محاولات تسجيل الدخول المسموح بها") {
    super(message, "RATE_LIMIT_EXCEEDED");
    this.name = "RateLimitExceededError";
  }
}

import bcrypt from "bcryptjs";

import { userRepository } from "@/repositories/user.repository";
import { activityService } from "@/services/activity.service";
import { createSession, destroySession } from "@/lib/auth/session";
import { checkRateLimit, recordFailedAttempt, clearRateLimit } from "@/lib/auth/rate-limit";
import { DUMMY_HASH } from "@/lib/auth/config";
import {
  InvalidCredentialsError,
  RateLimitExceededError,
} from "@/lib/auth/errors";
import type { AuthenticatedUser } from "@/types/auth";

/* ============================================
   Auth Service
   Business logic for authentication flows.
   Uses userRepository for DB access and
   activityService for audit logging.
   ============================================ */

export const authService = {
  /**
   * Authenticate a user with email and password.
   *
   * Security measures:
   * - Rate limited per IP
   * - Timing attack prevention (always runs bcrypt.compare)
   * - Does not reveal whether email exists
   * - Logs all attempts to audit log
   *
   * @returns The authenticated user (without password).
   * @throws InvalidCredentialsError | RateLimitExceededError
   */
  async login(
    email: string,
    password: string,
    options?: { ip?: string; userAgent?: string }
  ): Promise<AuthenticatedUser> {
    const rateLimitKey = options?.ip ?? email;

    checkRateLimit(rateLimitKey);

    const user = await userRepository.findByEmail(email);

    // Always run bcrypt.compare — even if user not found —
    // to prevent timing attacks that reveal email existence.
    const hashToCompare = user?.password ?? DUMMY_HASH;
    const isValid = await bcrypt.compare(password, hashToCompare);

    if (!user || !isValid) {
      recordFailedAttempt(rateLimitKey);

      // Log failed login attempt (without revealing whether email exists)
      if (user) {
        await activityService.log({
          userId: user.id,
          type: "LOGIN",
          entity: "auth",
          entityId: user.id,
          metadata: {
            success: false,
            ip: options?.ip,
            userAgent: options?.userAgent,
          },
        });
      }

      throw new InvalidCredentialsError();
    }

    // Success — clear rate limit and create session
    clearRateLimit(rateLimitKey);

    await createSession({
      id: user.id,
      email: user.email,
      name: user.name,
      role: user.role,
      avatar: user.avatar,
    });

    // Log successful login
    await activityService.log({
      userId: user.id,
      type: "LOGIN",
      entity: "auth",
      entityId: user.id,
      metadata: {
        success: true,
        ip: options?.ip,
        userAgent: options?.userAgent,
      },
    });

    return {
      id: user.id,
      email: user.email,
      name: user.name,
      role: user.role,
      avatar: user.avatar,
    };
  },

  /**
   * Log out the current user by destroying the session
   * and logging the event.
   */
  async logout(userId?: string): Promise<void> {
    await destroySession();

    if (userId) {
      await activityService.log({
        userId,
        type: "LOGOUT",
        entity: "auth",
        entityId: userId,
        metadata: {},
      });
    }
  },
};

import { createClient } from "@supabase/supabase-js";

/**
 * Supabase admin client using the service role key.
 *
 * Bypasses Row Level Security — use ONLY on the server for
 * privileged operations (webhooks, system jobs, seeds).
 * NEVER expose this client to the browser.
 */
export function createSupabaseAdminClient() {
  return createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!,
    {
      auth: {
        autoRefreshToken: false,
        persistSession: false,
      },
    }
  );
}

import { createBrowserClient } from "@supabase/ssr";

/**
 * Supabase browser client.
 *
 * Uses the anon key — safe for client-side usage.
 * Respects the user's session via cookies managed by @supabase/ssr.
 */
export function createSupabaseBrowserClient() {
  return createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  );
}

import { createServerClient } from "@supabase/ssr";
import { cookies } from "next/headers";

/**
 * Supabase server client for Server Components, Server Actions, and Route Handlers.
 *
 * Uses the anon key with cookie-based session management.
 */
export async function createSupabaseServerClient() {
  const cookieStore = await cookies();

  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll();
        },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) =>
              cookieStore.set(name, value, options)
            );
          } catch {
            // Called from a Server Component — safe to ignore
            // if session refresh is handled by middleware.
          }
        },
      },
    }
  );
}

"use client";

import {
  createContext,
  useContext,
  useState,
  useCallback,
  type ReactNode,
} from "react";

import type { SessionUser, SessionStatus } from "@/types/auth";

type SessionContextValue = {
  user: SessionUser;
  status: SessionStatus;
  setUser: (user: SessionUser) => void;
  setStatus: (status: SessionStatus) => void;
};

const SessionContext = createContext<SessionContextValue | undefined>(
  undefined
);

export function SessionProvider({
  children,
  initialUser = null,
}: {
  children: ReactNode;
  initialUser?: SessionUser;
}) {
  const [user, setUser] = useState<SessionUser>(initialUser);
  const [status, setStatus] = useState<SessionStatus>(
    initialUser ? "authenticated" : "unauthenticated"
  );

  const handleSetUser = useCallback((value: SessionUser) => {
    setUser(value);
    setStatus(value ? "authenticated" : "unauthenticated");
  }, []);

  return (
    <SessionContext.Provider
      value={{ user, status, setUser: handleSetUser, setStatus }}
    >
      {children}
    </SessionContext.Provider>
  );
}

export function useSession() {
  const context = useContext(SessionContext);
  if (!context) {
    throw new Error("useSession must be used within a SessionProvider");
  }
  return context;
}

import type { UserRole as PrismaUserRole } from "@prisma/client";

/* ============================================
   Auth Types
   Aligned with the Prisma UserRole enum.
   ============================================ */

export type UserRole = PrismaUserRole;

export type AuthenticatedUser = {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  avatar?: string | null;
};

export type SessionUser = AuthenticatedUser | null;

export type SessionStatus = "loading" | "authenticated" | "unauthenticated";

import { z } from "zod";

/* ── Common field schemas (reusable) ──────── */

export const emailSchema = z
  .string()
  .min(1, "البريد الإلكتروني مطلوب")
  .email("البريد الإلكتروني غير صالح");

export const passwordSchema = z
  .string()
  .min(8, "كلمة المرور يجب أن تكون 8 أحرف على الأقل")
  .regex(/[A-Z]/, "يجب أن تحتوي على حرف كبير واحد على الأقل")
  .regex(/[a-z]/, "يجب أن تحتوي على حرف صغير واحد على الأقل")
  .regex(/[0-9]/, "يجب أن تحتوي على رقم واحد على الأقل");

export const nameSchema = z
  .string()
  .min(2, "الاسم يجب أن يكون حرفين على الأقل")
  .max(50, "الاسم يجب أن يكون 50 حرفاً كحد أقصى");

export const phoneSchema = z
  .string()
  .regex(
    /^(\+?966|0)?5\d{8}$/,
    "رقم الهاتف غير صالح — مثال: 05xxxxxxxx"
  )
  .optional()
  .or(z.literal(""));

/* ── Composite schemas ───────────────────── */

export const loginSchema = z.object({
  email: emailSchema,
  password: z.string().min(1, "كلمة المرور مطلوبة"),
});

export const registerSchema = z
  .object({
    name: nameSchema,
    email: emailSchema,
    password: passwordSchema,
    confirmPassword: z.string(),
  })
  .refine((data) => data.password === data.confirmPassword, {
    message: "كلمتا المرور غير متطابقتين",
    path: ["confirmPassword"],
  });

export type LoginInput = z.infer<typeof loginSchema>;
export type RegisterInput = z.infer<typeof registerSchema>;

